Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _fetcher = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await _fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // framework enforces 3s deadline
    public async Task FetchAsync_SlowServer_TimesOutViaCancellationToken()
    {
        _handler.Delay = TimeSpan.FromSeconds(30); // simulate slow server
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        // TestContext.CancellationToken fires when [Timeout] expires,
        // so the test will throw rather than hang for 30s.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return Response;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(3000)]` + `_testContext.CancellationToken` — the framework cancels the token when time expires |
| **Pre-cancelled token** | `cts.Cancel()` before calling, verifies the method respects cancellation immediately |
| **Async exceptions** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **No mocking library** | Custom `HttpMessageHandler` gives full control over responses and delays |
| **Sealed class + ctor init** | Fields are `readonly`, `TestContext` injected via constructor |

The critical insight: **always pass `TestContext.CancellationToken`** into async calls in tests with `[Timeout]`. Without it, a hanging call would block the test runner indefinitely — the timeout wouldn't be able to interrupt it.
